// src/pages/Contact.js
import React, { useState } from 'react';
import Stepper, { Step } from '../components/Stepper';
import Calculator from '../components/Calculator';
import { useLocalStorage } from '../hooks/useLocalStorage';

const TELEGRAM_LINK = 'https://t.me/vibedevmiddle';

// === НАСТРОЙКИ ТЕЛЕГРАМ БОТА ===
const BOT_TOKEN = '8122224069:AAG1bp0rTn_X5wmXxFP6gZ4Gp0SqRRcobXU';
const CHAT_IDS = [
  5863518468,  // Вадим (uc3rnam3) 
  8908033185   // Вадим (vibedevmiddle)
];

function Contact() {
  const [submissions, setSubmissions] = useLocalStorage('site_submissions_vadim', []);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [formData, setFormData] = useState({
    service: '',
    name: '',
    contact: '',
    msg: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showStepper, setShowStepper] = useState(false);

  const handleInputChange = (e) => {
    const { id, value } = e.target;
    setFormData(prev => ({ ...prev, [id]: value }));
  };

  // Отправка уведомления в Telegram с кнопкой
  const sendTelegramNotification = async (data) => {
    // Формируем ссылку на пользователя
    const username = data.contact.startsWith('@') ? data.contact : '@' + data.contact;
    const cleanUsername = data.contact.replace('@', '');
    
    // Текст сообщения
    const message = `📨 *Новая заявка с сайта VibeDev!*

👤 *Имя:* ${data.name}
📱 *Telegram:* ${username}
📂 *Услуга:* ${data.service}
📝 *Описание:* ${data.msg || 'Не указано'}

🕐 *Время:* ${new Date().toLocaleString('ru-RU', { 
  dateStyle: 'short', 
  timeStyle: 'medium' 
})}`;

    // Текст для предварительно заполненного сообщения
    const preFilledMessage = `Приветствую! Я по поводу вашей заявки на сайте VibeDev.
Услуга: ${data.service}
Ожидайте, скоро свяжусь с вами для уточнения деталей.`;

    // Кнопка для перехода в чат с клиентом
    const inlineKeyboard = {
      inline_keyboard: [
        [
          {
            text: `💬 Написать ${data.name}`,
            url: `https://t.me/${cleanUsername}?text=${encodeURIComponent(preFilledMessage)}`
          }
        ]
      ]
    };

    const results = [];
    
    for (const chatId of CHAT_IDS) {
      try {
        const response = await fetch(`https://api.telegram.org/bot${BOT_TOKEN}/sendMessage`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            chat_id: chatId,
            text: message,
            parse_mode: 'Markdown',
            reply_markup: inlineKeyboard,
            disable_web_page_preview: true,
          }),
        });
        
        const result = await response.json();
        results.push({ chatId, success: result.ok });
        
        if (!result.ok) {
          console.error(`Ошибка отправки для chat_id ${chatId}:`, result);
        }
      } catch (error) {
        console.error(`Ошибка сети для chat_id ${chatId}:`, error);
        results.push({ chatId, success: false, error: error.message });
      }
    }
    
    return results;
  };

  const handleSubmit = async () => {
    // Валидация
    if (!formData.service || !formData.name || !formData.contact || !formData.msg) {
      alert('Пожалуйста, заполните все поля');
      return;
    }
    if (!formData.contact.startsWith('@')) {
      alert('Telegram должен начинаться с @');
      return;
    }

    setIsSubmitting(true);

    try {
      // 1. Сохраняем в localStorage
      const now = new Date();
      const ts = now.toLocaleString('ru-RU', { dateStyle: 'short', timeStyle: 'short' });
      setSubmissions(prev => [{ ...formData, ts }, ...prev]);

      // 2. Отправляем уведомление в Telegram
      const results = await sendTelegramNotification(formData);
      
      const anySuccess = results.some(r => r.success);
      
      if (anySuccess) {
        setIsModalOpen(true);
        setFormData({ service: '', name: '', contact: '', msg: '' });
        setShowStepper(false);
      } else {
        console.error('Все попытки отправки в Telegram провалились:', results);
        alert('Заявка сохранена, но не удалось отправить уведомление в Telegram.');
        setIsModalOpen(true);
        setFormData({ service: '', name: '', contact: '', msg: '' });
        setShowStepper(false);
      }

    } catch (error) {
      console.error('Ошибка отправки:', error);
      alert('Произошла ошибка при отправке. Попробуйте позже или напишите в Telegram.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleApplyCalculatorData = (calcText, serviceLabel) => {
    setFormData(prev => ({
      ...prev,
      service: serviceLabel || prev.service,
      msg: calcText + (prev.msg || '')
    }));
    // Открываем степпер
    setShowStepper(true);
    // Скроллим к степперу
    setTimeout(() => {
      document.querySelector('.stepper-outer-container')?.scrollIntoView({ behavior: 'smooth' });
    }, 300);
  };

  const serviceOptions = ['Создание сайтов', 'Курсовые работы', 'Telegram боты', 'Дизайн', 'Другое'];

  return (
    <main className="contact-content">
      <section className="card">
        <div className="contact-header">
          <div className="header-icon">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="var(--accent-2)" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M22 2L11 13" />
              <path d="M22 2l-7 20-4-9-9-4 20-7z" />
            </svg>
          </div>
          <h2>Создать заявку</h2>
          <span className="vibedev-tag" style={{ marginLeft: 'auto' }}>✦ VibeDev</span>
        </div>
        <p style={{ fontWeight: 400, letterSpacing: '0.01em', color: 'var(--muted)', marginBottom: 24 }}>
          Заполните форму — заявка отправится и сохранится
        </p>

        {/* Кнопка "Составить заявку" */}
        <div style={{ textAlign: 'center', marginBottom: 32 }}>
          <button
            className="order-btn"
            onClick={() => {
              setShowStepper(true);
              setTimeout(() => {
                document.querySelector('.stepper-outer-container')?.scrollIntoView({ behavior: 'smooth' });
              }, 300);
            }}
            style={{ padding: '16px 40px', fontSize: '18px' }}
          >
            <span>
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ marginRight: 8 }}>
                <path d="M22 2L11 13" />
                <path d="M22 2l-7 20-4-9-9-4 20-7z" />
              </svg>
              Составить заявку
            </span>
          </button>
        </div>

        {/* Степпер - появляется после нажатия на кнопку */}
        {showStepper && (
          <div style={{ width: '100%', marginTop: 16 }}>
            <Stepper
              initialStep={1}
              onStepChange={(step) => console.log('Step changed to:', step)}
              onFinalStepCompleted={handleSubmit}
              backButtonText="Назад"
              nextButtonText="Далее"
            >
              <Step>
                <h3 style={{ marginBottom: 16 }}>Выберите услугу</h3>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}>
                  {serviceOptions.map(opt => (
                    <button
                      key={opt}
                      className={`service-option ${formData.service === opt ? 'active' : ''}`}
                      onClick={() => setFormData(prev => ({ ...prev, service: opt }))}
                      style={{ 
                        padding: '12px 16px', 
                        borderRadius: 12, 
                        border: '1px solid var(--border)', 
                        background: formData.service === opt ? 'rgba(96,165,250,0.1)' : 'rgba(255,255,255,0.02)',
                        cursor: 'pointer', 
                        transition: 'var(--transition)', 
                        color: 'var(--text)', 
                        fontFamily: 'var(--font-body)',
                        borderColor: formData.service === opt ? 'var(--accent-2)' : 'var(--border)'
                      }}
                    >
                      {opt}
                    </button>
                  ))}
                </div>
              </Step>
              <Step>
                <h3 style={{ marginBottom: 16 }}>Контактные данные</h3>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                  <div>
                    <label style={{ fontSize: 14, color: 'var(--muted)', display: 'block', marginBottom: 4 }}>Ваше имя</label>
                    <input
                      id="name"
                      className="fancy-input"
                      placeholder="Как к вам обращаться?"
                      value={formData.name}
                      onChange={handleInputChange}
                      style={{ width: '100%' }}
                    />
                  </div>
                  <div>
                    <label style={{ fontSize: 14, color: 'var(--muted)', display: 'block', marginBottom: 4 }}>Telegram</label>
                    <input
                      id="contact"
                      className="fancy-input"
                      placeholder="@username"
                      value={formData.contact}
                      onChange={handleInputChange}
                      style={{ width: '100%' }}
                    />
                  </div>
                </div>
              </Step>
              <Step>
                <h3 style={{ marginBottom: 16 }}>Описание задачи</h3>
                <div>
                  <label style={{ fontSize: 14, color: 'var(--muted)', display: 'block', marginBottom: 4 }}>Подробное описание</label>
                  <textarea
                    id="msg"
                    className="fancy-textarea"
                    placeholder="Опишите подробнее, что нужно сделать..."
                    rows="5"
                    value={formData.msg}
                    onChange={handleInputChange}
                    style={{ width: '100%' }}
                  />
                </div>
              </Step>
              <Step>
                <h3 style={{ marginBottom: 16 }}>Проверка данных</h3>
                <div style={{ background: 'rgba(255,255,255,0.02)', borderRadius: 12, padding: 16, border: '1px solid var(--border)' }}>
                  <p><strong>Услуга:</strong> {formData.service || 'Не выбрана'}</p>
                  <p><strong>Имя:</strong> {formData.name || 'Не указано'}</p>
                  <p><strong>Telegram:</strong> {formData.contact || 'Не указан'}</p>
                  <p><strong>Описание:</strong> {formData.msg || 'Не указано'}</p>
                </div>
                <p style={{ color: 'var(--muted)', fontSize: 14, marginTop: 12, textAlign: 'center' }}>
                  Нажмите "Завершить" для отправки заявки
                </p>
              </Step>
            </Stepper>
          </div>
        )}

        {/* Калькулятор - под кнопкой */}
        <div style={{ marginTop: 40, paddingTop: 32, borderTop: '1px solid var(--border)' }}>
          <div className="contact-header">
            <div className="header-icon">
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="var(--accent-2)" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <circle cx="12" cy="12" r="10" />
                <path d="M12 6v6l4 2" />
              </svg>
            </div>
            <h2 style={{ fontSize: 24 }}>Калькулятор стоимости</h2>
            <span className="vibedev-tag" style={{ marginLeft: 'auto' }}>✦ VibeDev</span>
          </div>
          <p style={{ fontWeight: 400, letterSpacing: '0.01em', color: 'var(--muted)', marginBottom: 16 }}>
            Выберите параметры и получите примерную стоимость проекта
          </p>
          <Calculator onApplyToForm={handleApplyCalculatorData} />
        </div>

        {/* Список заявок */}
        <div style={{ marginTop: 32 }}>
          <h3 style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 20, fontFamily: 'var(--font-heading)' }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="var(--accent-2)" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14" />
              <polyline points="22 4 12 14.01 9 11.01" />
            </svg>
            Отправленные заявки
            <span style={{ fontSize: 13, fontWeight: 400, color: 'var(--muted)', fontFamily: 'var(--font-body)' }}>
              ({submissions.length})
            </span>
          </h3>
          {submissions.length === 0 ? (
            <div style={{ color: 'var(--muted)', textAlign: 'center', padding: 20, fontWeight: 400 }}>
              Заявок пока нет
            </div>
          ) : (
            <div className="submissions">
              {submissions.map((s, i) => (
                <div key={i} className="submission-item">
                  <div className="submission-icon">
                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                      <path d="M22 2L11 13" />
                      <path d="M22 2l-7 20-4-9-9-4 20-7z" />
                    </svg>
                  </div>
                  <div className="submission-content">
                    <div className="submission-title">{s.name || 'Без имени'}</div>
                    <div className="submission-meta">{s.service || 'Без услуги'} · {s.ts || ''}</div>
                    <div className="submission-text">{s.msg || ''}</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Модальное окно */}
        {isModalOpen && (
          <div className="modal-overlay open" onClick={() => setIsModalOpen(false)}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
              <span className="modal-icon">
                <svg width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="var(--accent)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14" />
                  <polyline points="22 4 12 14.01 9 11.01" />
                </svg>
              </span>
              <div className="modal-title">Ваша заявка отправлена!</div>
              <div className="modal-subtitle">
                Ожидайте ответа в мессенджере. <strong>Менеджер скоро вам напишет.</strong><br />
                Либо если вопрос срочный — напишите сами:
              </div>
              <div className="modal-buttons">
                <a href={TELEGRAM_LINK} target="_blank" rel="noopener noreferrer" className="modal-btn modal-btn-telegram">
                  <i className="fab fa-telegram"></i> Написать в Telegram
                </a>
                <button className="modal-btn modal-btn-secondary" onClick={() => setIsModalOpen(false)}>Закрыть</button>
              </div>
              <div className="modal-divider">✦ VibeDev</div>
            </div>
          </div>
        )}
      </section>
    </main>
  );
}

export default Contact;