// src/pages/Faq.js
import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import FaqItem from '../components/FaqItem';

const TELEGRAM_LINK = 'https://t.me/vibedevmiddle';

function Faq() {
  const [search, setSearch] = useState('');
  const [category, setCategory] = useState('all');

  const faqs = [
    {
      question: 'Сколько стоят ваши услуги?',
      answer: 'Стоимость зависит от сложности проекта и объема работ. Примерные цены:<br>• Сайт-визитка: от 15 000 ₽<br>• Telegram бот: от 12 000 ₽<br>• Курсовая работа: от 8 000 ₽<br>• Дизайн: от 5 000 ₽<br><br>Точную стоимость обсуждаем индивидуально после ознакомления с задачей. Используйте <a href="/contact#calculator">калькулятор</a> для примерного расчета.',
      tag: '💰 Цены',
      category: 'prices'
    },
    {
      question: 'Как происходит процесс работы?',
      answer: '1. Вы оставляете заявку с описанием задачи<br>2. Мы обсуждаем детали в Telegram<br>3. Я готовлю ТЗ и оцениваю стоимость<br>4. Согласовываем сроки и начинаем работу<br>5. Вы получаете готовый результат + поддержку',
      tag: '⚙️ Процесс',
      category: 'process'
    },
    {
      question: 'Какие сроки выполнения?',
      answer: 'Сроки зависят от сложности:<br>• Простые проекты (сайт-визитка, простой бот): 3-5 дней<br>• Средние проекты (интернет-магазин, сложный бот): 7-14 дней<br>• Сложные проекты: от 2 недель<br><br>Возможно выполнение в срочном порядке (+40% к стоимости).',
      tag: '📅 Сроки',
      category: 'terms'
    },
    {
      question: 'Какие технологии вы используете?',
      answer: 'Веб-разработка: HTML5, CSS3, JavaScript, Python (Flask/Django)<br>Боты: Python (Aiogram, PyTelegramBotAPI)<br>Дизайн: Figma, Photoshop, Illustrator<br><br>Всегда использую современные и проверенные технологии.',
      tag: '🛠 Технические',
      category: 'tech'
    },
    {
      question: 'Нужна предоплата?',
      answer: 'Да, для крупных проектов требуется предоплата 30-50%. Для небольших заказов (до 10 000 ₽) работаем без предоплаты. Оплата принимается на карту или по договоренности.',
      tag: '💰 Цены',
      category: 'prices'
    },
    {
      question: 'Предоставляете ли вы гарантию?',
      answer: 'Да! Я предоставляю гарантию на все свои работы:<br>• Исправление багов бесплатно в течение 1 месяца<br>• Техническая поддержка 2 недели после сдачи<br>• Бесплатные правки по ТЗ (до сдачи)',
      tag: '⚙️ Процесс',
      category: 'process'
    },
    {
      question: 'Как с вами связаться?',
      answer: `Самый быстрый способ — <a href="${TELEGRAM_LINK}" target="_blank">Telegram @vibedevmiddle</a><br>Также можно оставить заявку через <a href="/contact">форму на сайте</a><br>Отвечаю обычно в течение 1-2 часов в рабочее время.`,
      tag: '📌 Другое',
      category: 'other'
    },
    {
      question: 'Можете помочь с защитой курсовой?',
      answer: 'Да! Я помогаю с:<br>• Написанием текста работы<br>• Созданием презентации<br>• Подготовкой к защите<br>• Поиском материалов<br><br>Мои клиенты успешно защищаются на оценки 4 и 5.',
      tag: '🛠 Технические',
      category: 'tech'
    },
    {
      question: 'Можно ли срочно сделать проект?',
      answer: 'Да, я беру срочные заказы. Стоимость увеличивается на 40% от базовой цены. Минимальный срок для срочного заказа — 24 часа для небольших проектов.',
      tag: '📅 Сроки',
      category: 'terms'
    },
    {
      question: 'Есть ли скидки?',
      answer: 'Да! Предоставляю скидки:<br>• 10% — постоянным клиентам<br>• 15% — при заказе комплексной услуги<br>• 20% — при повторном заказе в течение 3 месяцев<br><br>Следите за акциями в Telegram!',
      tag: '💰 Цены',
      category: 'prices'
    }
  ];

  const categories = [
    { value: 'all', label: 'Все' },
    { value: 'prices', label: 'Цены' },
    { value: 'process', label: 'Процесс' },
    { value: 'terms', label: 'Сроки' },
    { value: 'tech', label: 'Технические' },
    { value: 'other', label: 'Другое' },
  ];

  const filteredFaqs = faqs.filter(item => {
    const matchesSearch = search === '' ||
      item.question.toLowerCase().includes(search.toLowerCase()) ||
      item.answer.toLowerCase().includes(search.toLowerCase()) ||
      item.tag.toLowerCase().includes(search.toLowerCase());
    const matchesCategory = category === 'all' || item.category === category;
    return matchesSearch && matchesCategory;
  });

  return (
    <main>
      <section className="card">
        <div className="contact-header">
          <div className="header-icon">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="var(--accent-2)" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
              <circle cx="12" cy="12" r="10" />
              <path d="M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3" />
              <line x1="12" y1="17" x2="12.01" y2="17" />
            </svg>
          </div>
          <h2>Часто задаваемые вопросы</h2>
          <span className="vibedev-tag" style={{ marginLeft: 'auto' }}>✦ VibeDev</span>
        </div>
        <p style={{ fontWeight: 400, letterSpacing: '0.01em', color: 'var(--muted)' }}>
          Ответы на самые популярные вопросы
        </p>

        <div className="faq-search">
          <span className="search-icon">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <circle cx="11" cy="11" r="8" />
              <line x1="21" y1="21" x2="16.65" y2="16.65" />
            </svg>
          </span>
          <input
            type="text"
            placeholder="Поиск по вопросам..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          {search && (
            <span className="clear-search visible" onClick={() => setSearch('')}>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <line x1="18" y1="6" x2="6" y2="18" />
                <line x1="6" y1="6" x2="18" y2="18" />
              </svg>
            </span>
          )}
        </div>

        <div className="faq-categories">
          {categories.map(cat => (
            <button
              key={cat.value}
              className={`cat-btn ${category === cat.value ? 'active' : ''}`}
              onClick={() => setCategory(cat.value)}
            >
              {cat.label}
            </button>
          ))}
        </div>

        <div id="faqList">
          {filteredFaqs.map((faq, i) => (
            <FaqItem key={i} {...faq} isOpen={i === 0 && search === '' && category === 'all'} />
          ))}
          {filteredFaqs.length === 0 && (
            <div className="no-results show">
              <div className="icon">
                <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                  <circle cx="11" cy="11" r="8" />
                  <line x1="21" y1="21" x2="16.65" y2="16.65" />
                </svg>
              </div>
              <p>Ничего не найдено по вашему запросу</p>
              <p style={{ fontSize: 13 }}>Попробуйте изменить поисковый запрос</p>
            </div>
          )}
        </div>

        <div style={{ textAlign: 'center', marginTop: 24 }}>
          <Link to="/contact" className="order-btn">
            <span>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ marginRight: 6 }}>
                <path d="M22 2L11 13" />
                <path d="M22 2l-7 20-4-9-9-4 20-7z" />
              </svg>
              Не нашли ответ? Создать заявку
            </span>
          </Link>
          <div style={{ marginTop: 12 }}>
            <span className="vibedev-tag">✦ VibeDev</span>
          </div>
        </div>
      </section>
    </main>
  );
}

export default Faq;