// src/components/ReviewCard.js
import React from 'react';

function ReviewCard({ name, date, text, service, avatar, stars = 5 }) {
  return (
    <div className="review-card" data-service={service}>
      <div className="review-quote">"</div>
      <div className="review-header">
        <div className="review-avatar">{avatar || name.charAt(0)}</div>
        <div>
          <div className="review-name">{name}</div>
          <div className="review-date">{date}</div>
        </div>
      </div>
      <div className="review-stars">{'★'.repeat(stars)}</div>
      <div className="review-text">{text}</div>
      <span className="review-service">{service}</span>
    </div>
  );
}

export default ReviewCard;