// src/components/Calculator.js
import React, { useState, useEffect } from 'react';

function Calculator({ onApplyToForm }) {
  const [service, setService] = useState({ price: 15000, value: 'site', label: 'Сайт' });
  const [complexity, setComplexity] = useState({ multiplier: 1, label: 'Лёгкая' });
  const [urgency, setUrgency] = useState({ multiplier: 1, label: 'Обычные' });
  const [people, setPeople] = useState(0);
  const [discount, setDiscount] = useState(0);
  const [selectedExtras, setSelectedExtras] = useState({});
  const [total, setTotal] = useState(15000);

  const extrasData = {
    site: [
      { id: 'adaptive', label: 'Адаптив', price: 3000 },
      { id: 'admin', label: 'Админ-панель', price: 5000 },
      { id: 'seo', label: 'SEO-оптимизация', price: 4000 },
      { id: 'support', label: 'Поддержка 1 мес', price: 2000 }
    ],
    course: [
      { id: 'legal', label: 'Юридические темы', price: 0, percent: 25 },
      { id: 'medical', label: 'Медицинские темы', price: 0, percent: 30 }
    ],
    bot: [
      { id: 'admin_panel', label: 'Админ-панель', price: 4000 },
      { id: 'analytics', label: 'Аналитика', price: 3000 },
      { id: 'support', label: 'Поддержка 1 мес', price: 2000 }
    ],
    design: [
      { id: 'source', label: 'Исходники (PSD/Figma)', price: 2000 },
      { id: 'brandbook', label: 'Брендбук', price: 4000 },
      { id: 'adaptation', label: 'Адаптация под соцсети', price: 2500 }
    ],
    other: [
      { id: 'consultation', label: 'Консультация', price: 2000 },
      { id: 'support', label: 'Поддержка 1 мес', price: 2000 }
    ]
  };

  const serviceOptions = [
    { value: 'site', label: '🌐 Сайт', price: 15000 },
    { value: 'bot', label: '🤖 Telegram бот', price: 12000 },
    { value: 'course', label: '📚 Курсовая/ИП', price: 8000 },
    { value: 'design', label: '🎨 Дизайн', price: 5000 },
    { value: 'other', label: '💡 Другое', price: 10000 }
  ];

  const complexityOptions = [
    { value: 'easy', label: 'Лёгкая', multiplier: 1 },
    { value: 'medium', label: 'Средняя', multiplier: 1.5 },
    { value: 'hard', label: 'Сложная', multiplier: 2.5 }
  ];

  const urgencyOptions = [
    { value: 'normal', label: 'Обычные', multiplier: 1 },
    { value: 'urgent', label: 'Срочно (+40%)', multiplier: 1.4 }
  ];

  const getExtras = () => extrasData[service.value] || [];

  const toggleExtra = (extraId) => {
    setSelectedExtras(prev => {
      const newExtras = { ...prev };
      if (newExtras[extraId]) {
        delete newExtras[extraId];
      } else {
        const extra = getExtras().find(e => e.id === extraId);
        if (extra) {
          newExtras[extraId] = { price: extra.price || 0, percent: extra.percent || 0, label: extra.label };
        }
      }
      return newExtras;
    });
  };

  useEffect(() => {
    let basePrice = service.price;
    let totalPrice = basePrice * complexity.multiplier * urgency.multiplier;

    let extraTotal = 0;
    let extraPercent = 0;

    for (const key in selectedExtras) {
      const extra = selectedExtras[key];
      if (extra.percent) {
        extraPercent += extra.percent;
      } else if (extra.price) {
        extraTotal += extra.price;
      }
    }

    totalPrice = totalPrice * (1 + extraPercent / 100) + extraTotal;

    const peopleCount = Math.min(Math.max(people, 0), 6);
    const discountPercent = peopleCount * 10;
    setDiscount(discountPercent);

    const finalTotal = totalPrice * (1 - discountPercent / 100);
    setTotal(Math.round(finalTotal));
  }, [service, complexity, urgency, people, selectedExtras]);

  const getExtrasList = () => {
    const list = [];
    for (const key in selectedExtras) {
      const extra = selectedExtras[key];
      if (extra.percent) {
        list.push(extra.label + ' (+' + extra.percent + '%)');
      } else if (extra.price) {
        list.push(extra.label + ' (+' + extra.price.toLocaleString() + '₽)');
      }
    }
    return list;
  };

  const handleApplyToForm = () => {
    const extrasList = getExtrasList().join(', ') || 'Нет';
    const calcText = `--- Данные из калькулятора ---
Услуга: ${service.label}
Сложность: ${complexity.label}
Сроки: ${urgency.label}
Дополнительно: ${extrasList}
${discount > 0 ? `Скидка: ${discount}% (приведено ${people} чел.)\n` : ''}
Итоговая стоимость: ${total.toLocaleString('ru-RU')} ₽
---
`;
    if (onApplyToForm) {
      onApplyToForm(calcText, service.label);
    }
  };

  return (
    <div className="calculator-grid">
      <div className="calculator-full-width">
        <label className="note-small">Тип услуги</label>
        <div className="calculator-options-row">
          {serviceOptions.map(opt => (
            <button
              key={opt.value}
              className={`calculator-option ${service.value === opt.value ? 'active' : ''}`}
              onClick={() => setService({ price: opt.price, value: opt.value, label: opt.label })}
            >
              {opt.label}
            </button>
          ))}
        </div>
      </div>

      <div className="calculator-half-width">
        <label className="note-small">Сложность</label>
        <div className="calculator-options-row">
          {complexityOptions.map(opt => (
            <button
              key={opt.value}
              className={`calculator-option ${complexity.value === opt.value ? 'active' : ''}`}
              onClick={() => setComplexity({ multiplier: opt.multiplier, label: opt.label })}
            >
              {opt.label}
            </button>
          ))}
        </div>
      </div>

      <div className="calculator-half-width">
        <label className="note-small">Сроки</label>
        <div className="calculator-options-row">
          {urgencyOptions.map(opt => (
            <button
              key={opt.value}
              className={`calculator-option ${urgency.value === opt.value ? 'active' : ''}`}
              onClick={() => setUrgency({ multiplier: opt.multiplier, label: opt.label })}
            >
              {opt.label}
            </button>
          ))}
        </div>
      </div>

      <div className="calculator-full-width">
        <label className="note-small">Дополнительные услуги</label>
        <div className="calculator-extras-row">
          {getExtras().map(extra => (
            <label key={extra.id} className="calculator-extra-label">
              <input
                type="checkbox"
                className="calculator-checkbox"
                checked={!!selectedExtras[extra.id]}
                onChange={() => toggleExtra(extra.id)}
              />
              {extra.label}
              {extra.percent ? ` (+${extra.percent}%)` : extra.price ? ` (+${extra.price.toLocaleString()}₽)` : ''}
            </label>
          ))}
        </div>
      </div>

      <div className="calculator-full-width">
        <div className="calculator-discount">
          <div className="calculator-discount-title">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#fbbf24" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M20.59 13.41l-7.17 7.17a2 2 0 0 1-2.83 0L2 12V2h10l8.59 8.59a2 2 0 0 1 0 2.82z" />
              <line x1="7" y1="7" x2="7.01" y2="7" />
            </svg>
            Приведи друга — получи скидку!
          </div>
          <div className="calculator-discount-input">
            <span className="calculator-discount-label">Количество приведенных людей:</span>
            <input
              type="number"
              min="0"
              max="6"
              value={people}
              onChange={(e) => setPeople(Math.min(Math.max(parseInt(e.target.value) || 0, 0), 6))}
              className="calculator-discount-input-field"
            />
            <span className="calculator-discount-label">=</span>
            <span className="calculator-discount-result">{Math.min(people * 10, 60)}%</span>
            <span className="calculator-discount-label">скидка</span>
          </div>
          <div className="calculator-discount-info">
            <strong>10%</strong> за каждого человека · Максимальная скидка <strong>60%</strong>
          </div>
        </div>
      </div>

      <div className="calculator-full-width">
        <div className="calculator-result">
          <div>
            <div className="calculator-result-label">Примерная стоимость</div>
            <div className="calculator-result-price">
              {total.toLocaleString('ru-RU')} ₽
            </div>
            <div className="calculator-result-detail">Скидка: {discount}%</div>
            <div className="calculator-result-detail">
              {service.label} | {complexity.label} | {urgency.label}
              {getExtrasList().length > 0 && ` | Доп: ${getExtrasList().join(', ')}`}
            </div>
          </div>
          <div className="calculator-result-buttons">
            <button className="order-btn" onClick={handleApplyToForm} style={{ padding: '14px 28px' }}>
              <span>
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ marginRight: 6 }}>
                  <path d="M22 2L11 13" />
                  <path d="M22 2l-7 20-4-9-9-4 20-7z" />
                </svg>
                Применить к заявке
              </span>
            </button>
            <button
              className="clear-btn"
              onClick={() => {
                setService({ price: 15000, value: 'site', label: 'Сайт' });
                setComplexity({ multiplier: 1, label: 'Лёгкая' });
                setUrgency({ multiplier: 1, label: 'Обычные' });
                setSelectedExtras({});
                setPeople(0);
              }}
              style={{ padding: '14px 20px' }}
            >
              <span className="clear-icon">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <polyline points="1 4 1 10 7 10" />
                  <path d="M3.51 15a9 9 0 1 0 2.13-9.36L1 10" />
                </svg>
              </span>
              <span className="clear-text">Сбросить</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Calculator;