// src/components/Particles.js
import React from 'react';

function Particles() {
  const particles = [
    { left: '3vw', size: 28, delay: -6, dur: 22, tx: 60, scale: 1.2, color: 'rgba(110,231,183,0.14)' },
    { left: '25vw', size: 40, delay: -8, dur: 28, tx: -80, scale: 1.4, color: 'rgba(96,165,250,0.1)' },
    { left: '50vw', size: 32, delay: -4, dur: 24, tx: 40, scale: 1.3, color: 'rgba(139,92,246,0.08)' },
  ];

  return (
    <div className="particles" aria-hidden="true">
      {particles.map((p, i) => (
        <span
          key={i}
          style={{
            '--left': p.left,
            '--size': p.size + 'px',
            '--delay': p.delay + 's',
            '--dur': p.dur + 's',
            '--tx': p.tx + 'px',
            '--scale': p.scale,
            '--color': p.color,
          }}
        />
      ))}
    </div>
  );
}

export default Particles;